22	BOOL WeaselTrayIcon::Create(HWND hTargetWnd) {
23	  HMODULE hModule = GetModuleHandle(NULL);
24	  CIcon icon;
25	  icon.LoadIconW(IDI_ZH);
26	  BOOL bRet =
27	      CSystemTray::Create(hModule, NULL, WM_WEASEL_TRAY_NOTIFY,
28	                          get_weasel_ime_name().c_str(), icon, IDR_MENU_POPUP);
29	  if (hTargetWnd) {
30	    SetTargetWnd(hTargetWnd);
31	  }
32	  if (!m_style.display_tray_icon) {
33	    RemoveIcon();
34	  } else {
35	    AddIcon();
36	  }
37	  return bRet;
38	}
39	
40	void WeaselTrayIcon::Refresh() {
41	  if (!m_style.display_tray_icon &&
42	      !m_status.disabled)  // display notification when deploying
43	  {
44	    if (m_mode != INITIAL) {
45	      RemoveIcon();
46	      m_mode = INITIAL;
47	    }
48	    m_disabled = false;
49	    return;
50	  }
51	  WeaselTrayMode mode = m_status.disabled     ? DISABLED
52	                        : m_status.ascii_mode ? ASCII
53	                                              : ZHUNG;
54	  /* change icon, when
55	          1,mode changed
56	          2,icon changed
57	          3,both m_schema_zhung_icon and m_style.current_zhung_icon empty(for
58	     initialize) 4,both m_schema_ascii_icon and m_style.current_ascii_icon
59	     empty(for initialize)
60	  */
61	  if (mode != m_mode || m_schema_zhung_icon != m_style.current_zhung_icon ||
62	      (m_schema_zhung_icon.empty() && m_style.current_zhung_icon.empty()) ||
63	      m_schema_ascii_icon != m_style.current_ascii_icon ||
64	      (m_schema_ascii_icon.empty() && m_style.current_ascii_icon.empty())) {
65	    ShowIcon();
66	    m_mode = mode;
67	    m_schema_zhung_icon = m_style.current_zhung_icon;
68	    m_schema_ascii_icon = m_style.current_ascii_icon;
69	    if (mode == ASCII) {
70	      if (m_schema_ascii_icon.empty())
