74	CSystemTray::CSystemTray(
75	    HINSTANCE hInst,          // Handle to application instance
76	    HWND hParent,             // The window that will recieve tray notifications
77	    UINT uCallbackMessage,    // the callback message to send to parent
78	    LPCTSTR szToolTip,        // tray icon tooltip
79	    HICON icon,               // Handle to icon
80	    UINT uID,                 // Identifier of tray icon
81	    BOOL bHidden /*=FALSE*/,  // Hidden on creation?
82	    LPCTSTR szBalloonTip /*=NULL*/,      // Ballon tip (w2k only)
83	    LPCTSTR szBalloonTitle /*=NULL*/,    // Balloon tip title (w2k)
84	    DWORD dwBalloonIcon /*=NIIF_NONE*/,  // Ballon tip icon (w2k)
85	    UINT uBalloonTimeout /*=10*/)        // Balloon timeout (w2k)
86	{
87	  Initialise();
88	  Create(hInst, hParent, uCallbackMessage, szToolTip, icon, uID, bHidden,
89	         szBalloonTip, szBalloonTitle, dwBalloonIcon, uBalloonTimeout);
90	}
