457	BOOL CSystemTray::StepAnimation() {
458	  if (!m_IconList.size())
459	    return FALSE;
460	
461	  m_nCurrentIcon++;
462	  if (m_nCurrentIcon >= (int)m_IconList.size())
463	    m_nCurrentIcon = 0;
464	
465	  return SetIcon(m_IconList[m_nCurrentIcon]);
466	}
