722	
723	LRESULT CSystemTray::OnTimer(UINT nIDEvent) {
724	  if (nIDEvent != m_uIDTimer) {
725	    ASSERT(FALSE);
726	    return 0L;
727	  }
728	
729	  time_t CurrentTime;
730	  time(&CurrentTime);
731	
732	  time_t period = CurrentTime - m_StartTime;
733	  if (m_nAnimationPeriod > 0 && m_nAnimationPeriod < period) {
734	    StopAnimation();
735	    return 0L;
736	  }
737	
738	  StepAnimation();
739	
740	  return 0L;
741	}
