753	  if (uFlags == SPI_SETWORKAREA)
754	    InstallIconPending();
755	  return 0L;
756	}
757	#endif
758	
759	LRESULT CSystemTray::OnTrayNotification(WPARAM wParam, LPARAM lParam) {
760	  // Return quickly if its not for this tray icon
761	  if (wParam != m_tnd.uID)
762	    return 0L;
763	
764	  HWND hTargetWnd = GetTargetWnd();
765	  if (!hTargetWnd)
766	    return 0L;
767	
768	    // Clicking with right button brings up a context menu
769	#if defined(_WIN32_WCE)  //&& _WIN32_WCE < 211
770	  BOOL bAltPressed =
771	      ((GetKeyState(VK_MENU) & (1 << (sizeof(SHORT) * 8 - 1))) != 0);
772	  if (LOWORD(lParam) == WM_LBUTTONUP && bAltPressed)
773	#else
774	  if (LOWORD(lParam) == WM_RBUTTONUP)
775	#endif
776	  {
777	    HMENU hMenu = ::LoadMenu(m_hInstance, MAKEINTRESOURCE(m_tnd.uID));
778	    if (!hMenu)
779	      return 0;
780	
781	    HMENU hSubMenu = ::GetSubMenu(hMenu, 0);
782	    if (!hSubMenu) {
783	      ::DestroyMenu(hMenu);  // Be sure to Destroy Menu Before Returning
784	      return 0;
785	    }
786	
787	#ifndef _WIN32_WCE
788	    // Make chosen menu item the default (bold font)
789	    ::SetMenuDefaultItem(hSubMenu, m_DefaultMenuItemID, m_DefaultMenuItemByPos);
790	#endif
791	
792	    CustomizeMenu(hSubMenu);
793	
794	    // Display and track the popup menu
795	    POINT pos;
796	#ifdef _WIN32_WCE
797	    DWORD messagepos = ::GetMessagePos();
798	    pos.x = GET_X_LPARAM(messagepos);
799	    pos.y = GET_Y_LPARAM(messagepos);
800	#else
801	    GetCursorPos(&pos);
802	#endif
803	
804	    ::SetForegroundWindow(m_tnd.hWnd);
805	    ::TrackPopupMenu(hSubMenu, 0, pos.x, pos.y, 0, hTargetWnd, NULL);
806	
807	    // BUGFIX: See "PRB: Menus for Notification Icons Don't Work Correctly"
808	    ::PostMessage(m_tnd.hWnd, WM_NULL, 0, 0);
809	
810	    DestroyMenu(hMenu);
811	  }
812	#if defined(_WIN32_WCE)  //&& _WIN32_WCE < 211
813	  if (LOWORD(lParam) == WM_LBUTTONDBLCLK && bAltPressed)
814	#else
815	  else if (LOWORD(lParam) == WM_LBUTTONDBLCLK)
816	#endif
817	  {
818	    // double click received, the default action is to execute default menu item
819	    ::SetForegroundWindow(m_tnd.hWnd);
820	
821	    UINT uItem;
822	    if (m_DefaultMenuItemByPos) {
823	      HMENU hMenu = ::LoadMenu(m_hInstance, MAKEINTRESOURCE(m_tnd.uID));
824	      if (!hMenu)
825	        return 0;
826	
827	      HMENU hSubMenu = ::GetSubMenu(hMenu, 0);
828	      if (!hSubMenu)
829	        return 0;
830	      uItem = ::GetMenuItemID(hSubMenu, m_DefaultMenuItemID);
831	
832	      DestroyMenu(hMenu);
833	    } else
834	      uItem = m_DefaultMenuItemID;
835	
836	    ::PostMessage(hTargetWnd, WM_COMMAND, uItem, 0);
837	  }
838	
839	  return 1;
840	}
841	
842	// This is the global (static) callback function for all TrayIcon windows
843	LRESULT PASCAL CSystemTray::WindowProc(HWND hWnd,
844	                                       UINT message,
845	                                       WPARAM wParam,
846	                                       LPARAM lParam) {
847	  // The option here is to maintain a list of all TrayIcon windows,
848	  // and iterate through them. If you do this, remove these 3 lines.
849	  CSystemTray* pTrayIcon = m_pThis;
850	  if (pTrayIcon->GetSafeHwnd() != hWnd)
851	    return ::DefWindowProc(hWnd, message, wParam, lParam);
852	
853	  // If maintaining a list of TrayIcon windows, then the following...
854	  // pTrayIcon = GetFirstTrayIcon()
855	  // while (pTrayIcon != NULL)
856	  // {
857	  //    if (pTrayIcon->GetSafeHwnd() != hWnd) continue;
858	
859	  // Taskbar has been recreated - all TrayIcons must process this.
860	  if (message == CSystemTray::m_nTaskbarCreatedMsg)
861	    return pTrayIcon->OnTaskbarCreated(wParam, lParam);
862	
863	  // Animation timer
864	  if (message == WM_TIMER && wParam == pTrayIcon->GetTimerID())
865	    return pTrayIcon->OnTimer(wParam);
866	
867	  // Settings changed
868	  if (message == WM_SETTINGCHANGE && wParam == pTrayIcon->GetTimerID())
869	    return pTrayIcon->OnSettingChange(wParam, (LPCTSTR)lParam);
870	
871	  // Is the message from the icon for this TrayIcon?
872	  if (message == pTrayIcon->GetCallbackMessage())
873	    return pTrayIcon->OnTrayNotification(wParam, lParam);
874	
875	  //    pTrayIcon = GetNextTrayIcon();
876	  // }
877	
878	  // Message has not been processed, so default.
879	  return ::DefWindowProc(hWnd, message, wParam, lParam);
880	}
881	
882	void CSystemTray::InstallIconPending() {
883	  // Is the icon display pending, and it's not been set as "hidden"?
884	  if (!m_bShowIconPending || m_bHidden)
885	    return;
886	
887	  // Reset the flags to what was used at creation
888	  m_tnd.uFlags = m_uCreationFlags;
889	
890	  // Try and recreate the icon
891	  m_bHidden = !Shell_NotifyIcon(NIM_ADD, &m_tnd);
892	
893	  // If it's STILL hidden, then have another go next time...
894	  m_bShowIconPending = !m_bHidden;
895	
896	  ASSERT(m_bHidden == FALSE);
897	}
