899	/////////////////////////////////////////////////////////////////////////////
900	// For minimising/maximising from system tray
901	
902	BOOL CALLBACK FindTrayWnd(HWND hwnd, LPARAM lParam) {
903	  TCHAR szClassName[256];
904	  GetClassName(hwnd, szClassName, 255);
905	
906	  // Did we find the Main System Tray? If so, then get its size and keep going
907	  if (_tcscmp(szClassName, _T("TrayNotifyWnd")) == 0) {
908	    LPRECT lpRect = (LPRECT)lParam;
909	    ::GetWindowRect(hwnd, lpRect);
910	    return TRUE;
911	  }
912	
913	  // Did we find the System Clock? If so, then adjust the size of the rectangle
914	  // we have and quit (clock will be found after the system tray)
915	  if (_tcscmp(szClassName, _T("TrayClockWClass")) == 0) {
916	    LPRECT lpRect = (LPRECT)lParam;
917	    RECT rectClock;
918	    ::GetWindowRect(hwnd, &rectClock);
919	    // if clock is above system tray adjust accordingly
920	    if (rectClock.bottom < lpRect->bottom - 5)  // 10 = random fudge factor.
921	      lpRect->top = rectClock.bottom;
922	    else
923	      lpRect->right = rectClock.left;
924	    return FALSE;
925	  }
926	
927	  return TRUE;
928	}
929	
930	#ifndef _WIN32_WCE
931	void CSystemTray::GetTrayWndRect(LPRECT lprect) {
932	#define DEFAULT_RECT_WIDTH 150
933	#define DEFAULT_RECT_HEIGHT 30
934	
935	  HWND hShellTrayWnd = FindWindow(_T("Shell_TrayWnd"), NULL);
936	  if (hShellTrayWnd) {
937	    GetWindowRect(hShellTrayWnd, lprect);
938	    EnumChildWindows(hShellTrayWnd, FindTrayWnd, (LPARAM)lprect);
939	    return;
940	  }
941	  // OK, we failed to get the rect from the quick hack. Either explorer isn't
942	  // running or it's a new version of the shell with the window class names
943	  // changed (how dare Microsoft change these undocumented class names!) So, we
944	  // try to find out what side of the screen the taskbar is connected to. We
945	  // know that the system tray is either on the right or the bottom of the
946	  // taskbar, so we can make a good guess at where to minimize to
947	  APPBARDATA appBarData;
948	  appBarData.cbSize = sizeof(appBarData);
949	  if (SHAppBarMessage(ABM_GETTASKBARPOS, &appBarData)) {
950	    // We know the edge the taskbar is connected to, so guess the rect of the
951	    // system tray. Use various fudge factor to make it look good
952	    switch (appBarData.uEdge) {
953	      case ABE_LEFT:
954	      case ABE_RIGHT:
955	        // We want to minimize to the bottom of the taskbar
956	        lprect->top = appBarData.rc.bottom - 100;
957	        lprect->bottom = appBarData.rc.bottom - 16;
958	        lprect->left = appBarData.rc.left;
959	        lprect->right = appBarData.rc.right;
960	        break;
961	
962	      case ABE_TOP:
963	      case ABE_BOTTOM:
964	        // We want to minimize to the right of the taskbar
965	        lprect->top = appBarData.rc.top;
966	        lprect->bottom = appBarData.rc.bottom;
967	        lprect->left = appBarData.rc.right - 100;
968	        lprect->right = appBarData.rc.right - 16;
969	        break;
970	    }
971	    return;
972	  }
973	
974	  // Blimey, we really aren't in luck. It's possible that a third party shell
975	  // is running instead of explorer. This shell might provide support for the
976	  // system tray, by providing a Shell_TrayWnd window (which receives the
977	  // messages for the icons) So, look for a Shell_TrayWnd window and work out
978	  // the rect from that. Remember that explorer's taskbar is the Shell_TrayWnd,
979	  // and stretches either the width or the height of the screen. We can't rely
980	  // on the 3rd party shell's Shell_TrayWnd doing the same, in fact, we can't
981	  // rely on it being any size. The best we can do is just blindly use the
982	  // window rect, perhaps limiting the width and height to, say 150 square.
983	  // Note that if the 3rd party shell supports the same configuraion as
984	  // explorer (the icons hosted in NotifyTrayWnd, which is a child window of
985	  // Shell_TrayWnd), we would already have caught it above
986	  if (hShellTrayWnd) {
987	    ::GetWindowRect(hShellTrayWnd, lprect);
988	    if (lprect->right - lprect->left > DEFAULT_RECT_WIDTH)
989	      lprect->left = lprect->right - DEFAULT_RECT_WIDTH;
990	    if (lprect->bottom - lprect->top > DEFAULT_RECT_HEIGHT)
991	      lprect->top = lprect->bottom - DEFAULT_RECT_HEIGHT;
992	
993	    return;
994	  }
995	
996	  // OK. Haven't found a thing. Provide a default rect based on the current work
997	  // area
998	  SystemParametersInfo(SPI_GETWORKAREA, 0, lprect, 0);
999	  lprect->left = lprect->right - DEFAULT_RECT_WIDTH;
1000	  lprect->top = lprect->bottom - DEFAULT_RECT_HEIGHT;
1001	}
1002	
1003	// Check to see if the animation has been disabled (Matthew Ellis
1004	// <m.t.ellis@bigfoot.com>)
1005	BOOL CSystemTray::GetDoWndAnimation() {
1006	  ANIMATIONINFO ai;
1007	
1008	  ai.cbSize = sizeof(ai);
1009	  SystemParametersInfo(SPI_GETANIMATION, sizeof(ai), &ai, 0);
1010	
1011	  return ai.iMinAnimate ? TRUE : FALSE;
1012	}
1013	#endif
1014	
1015	BOOL CSystemTray::RemoveTaskbarIcon(HWND hWnd) {
1016	  // Create static invisible window
1017	  if (!::IsWindow(m_hWndInvisible)) {
1018	    // 2007-11-14 GONG
1019	    m_hWndInvisible = CreateWindowEx(
1020	        0, _T("Static"), _T(""), WS_POPUP, CW_USEDEFAULT, CW_USEDEFAULT,
1021	        CW_USEDEFAULT, CW_USEDEFAULT, NULL, 0, NULL, 0);
1022	
1023	    if (!m_hWndInvisible)
1024	      return FALSE;
1025	  }
1026	
1027	  SetParent(hWnd, m_hWndInvisible);
1028	
1029	  return TRUE;
1030	}
1031	
1032	void CSystemTray::MinimiseToTray(HWND hWnd) {
1033	#ifndef _WIN32_WCE
1034	  if (GetDoWndAnimation()) {
1035	    RECT rectFrom, rectTo;
1036	
1037	    GetWindowRect(hWnd, &rectFrom);
1038	    GetTrayWndRect(&rectTo);
1039	
1040	    DrawAnimatedRects(hWnd, IDANI_CAPTION, &rectFrom, &rectTo);
1041	  }
1042	
1043	  RemoveTaskbarIcon(hWnd);
1044	  SetWindowLong(hWnd, GWL_STYLE, GetWindowLong(hWnd, GWL_STYLE) & ~WS_VISIBLE);
1045	#endif
1046	}
1047	
1048	void CSystemTray::MaximiseFromTray(HWND hWnd) {
1049	#ifndef _WIN32_WCE
1050	  if (GetDoWndAnimation()) {
1051	    RECT rectTo;
1052	    ::GetWindowRect(hWnd, &rectTo);
1053	
1054	    RECT rectFrom;
1055	    GetTrayWndRect(&rectFrom);
1056	
1057	    ::SetParent(hWnd, NULL);
1058	    DrawAnimatedRects(hWnd, IDANI_CAPTION, &rectFrom, &rectTo);
1059	  } else
1060	    ::SetParent(hWnd, NULL);
1061	
1062	  SetWindowLong(hWnd, GWL_STYLE, GetWindowLong(hWnd, GWL_STYLE) | WS_VISIBLE);
1063	  RedrawWindow(
1064	      hWnd, NULL, NULL,
1065	      RDW_UPDATENOW | RDW_ALLCHILDREN | RDW_FRAME | RDW_INVALIDATE | RDW_ERASE);
1066	
1067	  // Move focus away and back again to ensure taskbar icon is recreated
1068	  if (::IsWindow(m_hWndInvisible))
1069	    SetActiveWindow(m_hWndInvisible);
1070	  SetActiveWindow(hWnd);
1071	  SetForegroundWindow(hWnd);
1072	#endif
1073	}
