BOOL CSystemTray::SetNotificationWnd(HWND hNotifyWnd) {
  if (!m_bEnabled)
    return FALSE;

  // Make sure Notification window is valid
  if (!hNotifyWnd || !::IsWindow(hNotifyWnd)) {
