361	#define MAP_PIPE_MSG_HANDLE(__msg, __wParam, __lParam) \
362	  {                                                    \
363	    auto lParam = __lParam;                            \
364	    auto wParam = __wParam;                            \
365	    LRESULT _result = 0;                               \
366	    switch (__msg) {
367	#define PIPE_MSG_HANDLE(__msg, __func)       \
368	  case __msg:                                \
369	    _result = __func(__msg, wParam, lParam); \
370	    break;
371	
372	#define END_MAP_PIPE_MSG_HANDLE(__result) \
373	  }                                       \
374	  __result = _result;                     \
375	  }
376	
377	template <typename _Resp>
378	void ServerImpl::HandlePipeMessage(PipeMessage pipe_msg, _Resp resp) {
379	  DWORD result;
380	
381	  MAP_PIPE_MSG_HANDLE(pipe_msg.Msg, pipe_msg.wParam, pipe_msg.lParam)
382	  PIPE_MSG_HANDLE(WEASEL_IPC_ECHO, OnEcho)
383	  PIPE_MSG_HANDLE(WEASEL_IPC_START_SESSION, OnStartSession)
384	  PIPE_MSG_HANDLE(WEASEL_IPC_END_SESSION, OnEndSession)
385	  PIPE_MSG_HANDLE(WEASEL_IPC_PROCESS_KEY_EVENT, OnKeyEvent)
386	  PIPE_MSG_HANDLE(WEASEL_IPC_SHUTDOWN_SERVER, OnShutdownServer)
387	  PIPE_MSG_HANDLE(WEASEL_IPC_FOCUS_IN, OnFocusIn)
388	  PIPE_MSG_HANDLE(WEASEL_IPC_FOCUS_OUT, OnFocusOut)
389	  PIPE_MSG_HANDLE(WEASEL_IPC_UPDATE_INPUT_POS, OnUpdateInputPosition)
390	  PIPE_MSG_HANDLE(WEASEL_IPC_START_MAINTENANCE, OnStartMaintenance)
391	  PIPE_MSG_HANDLE(WEASEL_IPC_END_MAINTENANCE, OnEndMaintenance)
392	  PIPE_MSG_HANDLE(WEASEL_IPC_COMMIT_COMPOSITION, OnCommitComposition)
393	  PIPE_MSG_HANDLE(WEASEL_IPC_CLEAR_COMPOSITION, OnClearComposition);
394	  PIPE_MSG_HANDLE(WEASEL_IPC_SELECT_CANDIDATE_ON_CURRENT_PAGE,
395	                  OnSelectCandidateOnCurrentPage);
396	  PIPE_MSG_HANDLE(WEASEL_IPC_HIGHLIGHT_CANDIDATE_ON_CURRENT_PAGE,
397	                  OnHighlightCandidateOnCurrentPage);
398	  PIPE_MSG_HANDLE(WEASEL_IPC_CHANGE_PAGE, OnChangePage);
399	  PIPE_MSG_HANDLE(WEASEL_IPC_TRAY_COMMAND, OnCommand);
400	  END_MAP_PIPE_MSG_HANDLE(result);
401	
402	  resp(result);
403	}
