408	void PipeServer::Listen(ServerHandler const& handler) {
409	  for (;;) {
410	    HANDLE pipe = INVALID_HANDLE_VALUE;
411	    try {
412	      boost::this_thread::interruption_point();
413	      pipe = _ConnectServerPipe(pname);
414	      boost::thread th(
415	          [&handler, pipe, this] { _ProcessPipeThread(pipe, handler); });
416	    } catch (DWORD ex) {
417	      _FinalizePipe(pipe);
418	    }
419	    boost::this_thread::interruption_point();
420	  }
421	}
422	
423	PipeServer::ServerRunner PipeServer::GetServerRunner(
424	    ServerHandler const& handler) {
425	  return [&handler, this]() { Listen(handler); };
426	}
427	
428	void PipeServer::_ProcessPipeThread(HANDLE pipe, ServerHandler const& handler) {
429	  try {
430	    for (;;) {
431	      Res msg;
432	      _Receive(pipe, &msg, sizeof(msg));
433	      handler(msg, [this, pipe](Msg resp) { _Send(pipe, resp); });
434	    }
435	  } catch (...) {
436	    _FinalizePipe(pipe);
437	  }
438	}
